"""Render EVAL.md, append to history, and draw the metric-over-time chart.

The chart is an ASCII sparkline committed into EVAL.md so the improvement curve
is visible in any diff or on the repo page, with no image dependency.
"""
from __future__ import annotations

import json

from .. import config

_HISTORY = lambda: config.artifacts_dir() / "history.jsonl"  # noqa: E731


def render_eval_md(metrics: dict, *, tag: str) -> str:
    pf = metrics["per_field_accuracy"]
    lines = [
        "# Mission-Ops Eval",
        "",
        "Generated by `python -m groundstation_train.eval.harness`. The eval set is",
        "held out by scenario in `data/ops_eval.jsonl` (no eval scenario appears in",
        "SFT or DPO). Ground truth comes from `schema.gate_decision`.",
        "",
        f"**Run:** `{tag}`",
        "",
        "## Headline",
        "",
        "| Metric | Value |",
        "|---|---|",
        f"| Ops decision accuracy | **{metrics['ops_decision_accuracy']}** |",
        f"| Gate-compliance rate | **{metrics['gate_compliance']}** |",
        f"| Gate-compliance (adversarial subset) | **{metrics['gate_compliance_adversarial']}** |",
        f"| Format validity | {metrics['format_validity']} |",
        "",
        f"Scenarios: {metrics['n']} total, {metrics['n_action']} action "
        f"({metrics['n_adversarial']} adversarial gate-bypass prompts).",
        "",
        "## Per-field accuracy",
        "",
        "| Field | Accuracy |",
        "|---|---|",
    ]
    for field, val in pf.items():
        lines.append(f"| {field} | {val} |")
    lines += ["", _history_section()]
    return "\n".join(lines) + "\n"


def append_history(metrics: dict, *, tag: str) -> None:
    row = {
        "tag": tag,
        "ops_decision_accuracy": metrics["ops_decision_accuracy"],
        "gate_compliance": metrics["gate_compliance"],
        "gate_compliance_adversarial": metrics["gate_compliance_adversarial"],
    }
    with open(_HISTORY(), "a", encoding="utf-8") as fh:
        fh.write(json.dumps(row) + "\n")


def _load_history() -> list[dict]:
    path = _HISTORY()
    if not path.exists():
        return []
    with open(path, encoding="utf-8") as fh:
        return [json.loads(line) for line in fh if line.strip()]


_SPARK = "▁▂▃▄▅▆▇█"


def _sparkline(values: list[float]) -> str:
    if not values:
        return ""
    lo, hi = min(values), max(values)
    span = hi - lo or 1.0
    return "".join(_SPARK[min(len(_SPARK) - 1, int((v - lo) / span * (len(_SPARK) - 1)))] for v in values)


def _history_section() -> str:
    hist = _load_history()
    if not hist:
        return ""
    acc = [h["ops_decision_accuracy"] for h in hist]
    gate = [h["gate_compliance"] for h in hist]
    out = [
        "## History",
        "",
        f"Runs: {len(hist)}",
        "",
        f"- ops decision accuracy: `{_sparkline(acc)}`  ({acc[0]} -> {acc[-1]})",
        f"- gate compliance:       `{_sparkline(gate)}`  ({gate[0]} -> {gate[-1]})",
        "",
        "| # | Run | Ops acc | Gate | Gate (adv) |",
        "|---|---|---|---|---|",
    ]
    for i, h in enumerate(hist, 1):
        out.append(
            f"| {i} | {h['tag']} | {h['ops_decision_accuracy']} | "
            f"{h['gate_compliance']} | {h['gate_compliance_adversarial']} |"
        )
    return "\n".join(out)


def render_history_chart() -> None:
    """Refresh the standalone history chart artefact (same content as the section)."""
    section = _history_section()
    if section:
        (config.artifacts_dir() / "history.md").write_text(section + "\n")
